// Read CSV from binary data or use test data
const items = $input.all();

// If webhook provided a file
if (items[0]?.binary?.data) {
  const csvText = Buffer.from(items[0].binary.data.data, 'base64').toString('utf-8');
  const lines = csvText.split('\n').filter(l => l.trim());
  const headers = lines[0].split(',').map(h => h.trim().replace(/^"|"$/g, ''));
  const rows = [];
  for (let i = 1; i < lines.length; i++) {
    const vals = lines[i].split(',').map(v => v.trim().replace(/^"|"$/g, ''));
    const row = {};
    headers.forEach((h, idx) => { row[h] = vals[idx] || ''; });
    rows.push({ json: row });
  }
  return rows;
}

// Test data (Turkish supplier CSV format)
return [
  { json: { 'Stok Kodu': 'TXT-001', 'Ürün Adı': 'pamuk yatak ortüsü 1mt', 'Kategori': 'yatak', 'Marka': 'ÖRNEK', 'Fiyat': '250', 'Stok': '15', 'Renk': 'beyaz', 'Boyut': '200x220', 'Malzeme': 'Pamuk' } },
  { json: { 'Stok Kodu': 'TXT-002', 'Ürün Adı': 'Banyo Havlusu', 'Kategori': 'havlu', 'Marka': 'ÖRNEK', 'Fiyat': '85', 'Stok': '', 'Renk': 'lacivert', 'Boyut': '50x90', 'Malzeme': 'Pamuk' } },
  { json: { 'Stok Kodu': 'TXT-003', 'Ürün Adı': 'nevresim takimi 2mt', 'Kategori': 'nevresim', 'Marka': '', 'Fiyat': '0', 'Stok': '5', 'Renk': 'kirmizi', 'Boyut': '200x220', 'Malzeme': 'Polyester' } },
  { json: { 'Stok Kodu': 'TXT-001', 'Ürün Adı': 'pamuk yatak ortüsü 1mt', 'Kategori': 'yatak', 'Marka': 'ÖRNEK', 'Fiyat': '250', 'Stok': '15', 'Renk': 'beyaz', 'Boyut': '200x220', 'Malzeme': 'Pamuk' } }
];

// Map Turkish supplier fields to internal format and validate
const FIELD_MAP = {
  'Stok Kodu': 'sku',
  'Ürün Adı': 'name',
  'Kategori': 'category',
  'Marka': 'brand',
  'Fiyat': 'price',
  'Stok': 'stock',
  'Renk': 'color',
  'Boyut': 'size',
  'Malzeme': 'material',
  'Açıklama': 'extra_info',
};

const results = [];
const errors = [];

for (const item of $input.all()) {
  const raw = item.json;
  const mapped = {};

  for (const [trKey, enKey] of Object.entries(FIELD_MAP)) {
    if (raw[trKey] !== undefined) mapped[enKey] = raw[trKey];
  }

  if (!mapped.sku || !mapped.name) {
    errors.push({ ...raw, _error: 'SKU veya Ürün Adı eksik' });
    continue;
  }

  mapped.price = mapped.price ? parseFloat(mapped.price) : null;
  mapped.stock = (mapped.stock !== undefined && mapped.stock !== '') ? parseInt(mapped.stock) : null;

  results.push({ json: mapped });
}

if (errors.length > 0) {
  const last = results[results.length - 1] || { json: {} };
  last.json._validation_errors = errors;
  if (results.length === 0) results.push(last);
}

return results;

const batch = $input.first().json;
if (batch.results) {
  return batch.results.map(r => ({ json: r }));
}
return $input.all();

const SHOPIFY_HEADERS = [
  'Handle','Title','Body (HTML)','Vendor','Product Category',
  'Type','Tags','Published','Option1 Name','Option1 Value',
  'Variant SKU','Variant Inventory Qty','Variant Price','Status'
];

const rows = [SHOPIFY_HEADERS.join(',')];
const errors = [];

for (const item of $input.all()) {
  const p = item.json;
  if (p.error && !p.description) {
    errors.push(p);
    continue;
  }
  const handle = (p.cleaned_name || p.name).toLowerCase().replace(/[^a-z0-9]+/g, '-');
  const row = [
    handle,
    `"${(p.cleaned_name || p.name).replace(/"/g, '""')}"`,
    `"${(p.description || '').replace(/"/g, '""')}"`,
    `"${p.cleaned_brand || 'Generic'}"`,
    `"${p.cleaned_category || 'Genel Tekstil'}"`,
    `"${p.cleaned_category || 'Genel Tekstil'}"`,
    '',
    'true',
    'Renk',
    `"${p.cleaned_color || 'Standart'}"`,
    p.sku,
    p.cleaned_stock ?? 0,
    p.price ?? '',
    'active'
  ];
  rows.push(row.join(','));

  if (p.error) errors.push({ sku: p.sku, error: p.error });
}

return [{ json: { csv: rows.join('\n'), error_report: errors } }];

const item = $input.first().json;
const csvBuffer = Buffer.from(item.csv, 'utf-8');
const timestamp = new Date().toISOString().replace(/[:.]/g, '-').slice(0, 19);
const errorBuffer = Buffer.from(JSON.stringify(item.error_report, null, 2), 'utf-8');

return [{
  json: {
    csv_filename: `shopify_import_${timestamp}.csv`,
    error_filename: `error_report_${timestamp}.json`,
    total_products: item.csv.split('\n').length - 1,
    total_errors: item.error_report.length,
  },
  binary: {
    shopify_csv: {
      data: csvBuffer.toString('base64'),
      mimeType: 'text/csv',
      fileName: `shopify_import_${timestamp}.csv`,
    },
    error_report: {
      data: errorBuffer.toString('base64'),
      mimeType: 'application/json',
      fileName: `error_report_${timestamp}.json`,
    }
  }
}];
